#!/usr/bin/env bash
set -euo pipefail

AMB_ROOT=$(cd "$(dirname "$0")/.." && pwd)
cd "$AMB_ROOT"

: "${AMB_API_IMAGE:?}"
: "${AMB_WEB_IMAGE:?}"

if [ ! -f .env ]; then
  echo "Missing $AMB_ROOT/.env" >&2
  exit 1
fi

cat > .env.images <<EOF
# autogenerated by remote-pull-and-up.sh
AMB_API_IMAGE=${AMB_API_IMAGE}
AMB_WEB_IMAGE=${AMB_WEB_IMAGE}
EOF
chmod 600 .env.images 2>/dev/null || true

echo "=== Pulling images ==="
docker compose -f "$AMB_ROOT/docker-compose.yml" --env-file .env --env-file .env.images pull

if [ "${AMB_SKIP_MIGRATION:-0}" != "1" ]; then
  echo "=== DB migrations ==="
  bash "$AMB_ROOT/bin/run-migration.sh"
else
  echo "=== Migrations skipped (AMB_SKIP_MIGRATION=1) ==="
fi

echo "=== Up ==="
docker compose -f "$AMB_ROOT/docker-compose.yml" --env-file .env --env-file .env.images up -d --remove-orphans

echo "=== Status ==="
docker compose -f "$AMB_ROOT/docker-compose.yml" ps
echo "OK"
